import React, { useState, useEffect, useMemo } from "react";
import axios from "axios";
import VerticalGraph from "./VerticalGraph";

const Holdings = () => {
  const [allHoldings, setAllHoldings] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);

  useEffect(() => {
    const fetchHoldings = async () => {
      try {
        const res = await axios.get(
          `${process.env.REACT_APP_API_URL || "http://localhost:3002"}/allHoldings`
        );
        setAllHoldings(res.data || []);
      } catch (err) {
        console.error("Failed to fetch holdings:", err);
        setError("Failed to load holdings.");
      } finally {
        setLoading(false);
      }
    };

    fetchHoldings();
  }, []);

  // 🔥 Only include stocks you actually own
  const ownedStocks = useMemo(() => {
    return allHoldings.filter(stock => stock.qty && stock.qty > 0);
  }, [allHoldings]);

  // ==========================
  // Portfolio Calculations
  // ==========================
  const {
    totalInvestment,
    totalCurrentValue,
    totalPnL,
    totalPnLPercent,
  } = useMemo(() => {

    const investment = ownedStocks.reduce(
      (acc, stock) => acc + stock.avg * stock.qty,
      0
    );

    const currentValue = ownedStocks.reduce(
      (acc, stock) => acc + stock.price * stock.qty,
      0
    );

    const pnl = currentValue - investment;
    const pnlPercent = investment > 0 ? (pnl / investment) * 100 : 0;

    return {
      totalInvestment: investment,
      totalCurrentValue: currentValue,
      totalPnL: pnl,
      totalPnLPercent: pnlPercent,
    };
  }, [ownedStocks]);

  const totalClass = totalPnL >= 0 ? "profit" : "loss";

  // ==========================
  // Graph Data
  // ==========================
  const graphData = useMemo(() => {
    return {
      labels: ownedStocks.map(stock => stock.name),
      datasets: [
        {
          label: "Average Price",
          data: ownedStocks.map(stock => stock.avg),
          backgroundColor: "rgba(54, 162, 235, 0.6)",
        },
        {
          label: "Current Price",
          data: ownedStocks.map(stock => stock.price),
          backgroundColor: ownedStocks.map(stock =>
            stock.price >= stock.avg
              ? "rgba(75, 192, 192, 0.6)"
              : "rgba(255, 99, 132, 0.6)"
          ),
        },
      ],
    };
  }, [ownedStocks]);

  const formatCurrency = (value) =>
    value.toLocaleString("en-IN", {
      minimumFractionDigits: 2,
      maximumFractionDigits: 2,
    });

  if (loading) return <p>Loading holdings...</p>;
  if (error) return <p className="error">{error}</p>;

  return (
    <>
      <h3 className="title">Holdings ({ownedStocks.length})</h3>

      <div className="order-table">
        <table>
          <thead>
            <tr>
              <th>Instrument</th>
              <th>Qty.</th>
              <th>Avg. cost</th>
              <th>LTP</th>
              <th>Cur. val</th>
              <th>P&L</th>
              <th>Net chg.</th>
              <th>Day chg.</th>
            </tr>
          </thead>

          <tbody>
            {ownedStocks.map((stock) => {
              const currentValue = stock.price * stock.qty;
              const pnl = currentValue - stock.avg * stock.qty;

              return (
                <tr key={stock._id}>
                  <td>{stock.name}</td>
                  <td>{stock.qty}</td>
                  <td>₹{formatCurrency(stock.avg)}</td>
                  <td>₹{formatCurrency(stock.price)}</td>
                  <td>₹{formatCurrency(currentValue)}</td>
                  <td className={pnl >= 0 ? "profit" : "loss"}>
                    ₹{formatCurrency(pnl)}
                  </td>
                  <td>{stock.net}</td>
                  <td className={stock.isLoss ? "loss" : "profit"}>
                    {stock.day}
                  </td>
                </tr>
              );
            })}
          </tbody>
        </table>
      </div>

      {/* Portfolio Summary */}
      <div className="row">
        <div className="col">
          <h5>₹{formatCurrency(totalInvestment)}</h5>
          <p>Total investment</p>
        </div>

        <div className="col">
          <h5>₹{formatCurrency(totalCurrentValue)}</h5>
          <p>Current value</p>
        </div>

        <div className="col">
          <h5 className={totalClass}>
            ₹{formatCurrency(totalPnL)} ({totalPnLPercent.toFixed(2)}%)
          </h5>
          <p>P&L</p>
        </div>
      </div>

      <VerticalGraph data={graphData} />
    </>
  );
};

export default Holdings;
